create extension if not exists pgcrypto;
create type public.user_role as enum ('owner','manager','agent','photographer');
create type public.property_workflow_status as enum ('draft','review','approved','published','rejected','archived');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text,full_name text,role public.user_role not null default 'agent',active boolean not null default true,created_at timestamptz not null default now());
create table public.properties(id uuid primary key default gen_random_uuid(),property_code text unique,owner_user_id uuid not null references public.profiles(id),city text not null,property_type text not null,deal text not null,price text not null,title text not null,description text,bedrooms text,bathrooms text,area text,map_url text,latitude numeric,longitude numeric,workflow_status public.property_workflow_status not null default 'draft',reviewed_by uuid references public.profiles(id),reviewed_at timestamptz,published_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.property_images(id uuid primary key default gen_random_uuid(),property_id uuid not null references public.properties(id) on delete cascade,storage_path text not null,sort_order integer not null default 0,is_cover boolean not null default false,uploaded_by uuid not null references public.profiles(id),created_at timestamptz not null default now());
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,email,full_name,role) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'full_name',''),'agent'); return new; end; $$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
create sequence public.cm_property_seq start 1; create sequence public.bkk_property_seq start 1; create sequence public.pct_property_seq start 1; create sequence public.plk_property_seq start 1; create sequence public.nks_property_seq start 1;
create or replace function public.generate_property_code() returns trigger language plpgsql as $$ declare prefix text; seq_no bigint; begin if new.property_code is not null then return new; end if; prefix:=case new.city when 'Chiang Mai' then 'CM' when 'Bangkok' then 'BKK' when 'Phichit' then 'PCT' when 'Phitsanulok' then 'PLK' when 'Nakhon Sawan' then 'NKS' else 'OTH' end; seq_no:=case prefix when 'CM' then nextval('public.cm_property_seq') when 'BKK' then nextval('public.bkk_property_seq') when 'PCT' then nextval('public.pct_property_seq') when 'PLK' then nextval('public.plk_property_seq') when 'NKS' then nextval('public.nks_property_seq') else nextval('public.cm_property_seq') end; new.property_code:=prefix||'-'||lpad(seq_no::text,4,'0'); return new; end; $$;
create trigger before_property_insert_code before insert on public.properties for each row execute function public.generate_property_code();
alter table public.profiles enable row level security; alter table public.properties enable row level security; alter table public.property_images enable row level security;
create or replace function public.current_user_role() returns public.user_role language sql stable security definer set search_path=public as $$ select role from public.profiles where id=auth.uid(); $$;
create policy "profiles self read" on public.profiles for select to authenticated using(id=auth.uid() or public.current_user_role() in ('owner','manager'));
create policy "owner manages profiles" on public.profiles for all to authenticated using(public.current_user_role()='owner') with check(public.current_user_role()='owner');
create policy "property select" on public.properties for select to authenticated using(owner_user_id=auth.uid() or public.current_user_role() in ('owner','manager'));
create policy "property insert" on public.properties for insert to authenticated with check(owner_user_id=auth.uid() and workflow_status in ('draft','review'));
create policy "property update" on public.properties for update to authenticated using((owner_user_id=auth.uid() and workflow_status in ('draft','review','rejected')) or public.current_user_role() in ('owner','manager')) with check(owner_user_id=auth.uid() or public.current_user_role() in ('owner','manager'));
create policy "property delete" on public.properties for delete to authenticated using(public.current_user_role() in ('owner','manager'));
